        "-        qDebug() << UserManager::GetInstance()->GetPeerName();",
        "-        conv.name = UserManager::GetInstance()->GetPeerName();",
        "-        conv.icon = UserManager::GetInstance()->GetPeerIcon();",
        "-        conv.env = static_cast<int>(UserManager::GetInstance()->GetEnv());",
