        "-            val["name"] = item.name;",
        "-            val["icon"] = item.icon;",
        "-            val["status"] = item.status;",
        "-            val["deleted"] = item.deleted;",
        "-            val["pined"] = item.deleted;",
        "-            val["processed"] = item.processed;",
