        "+void MessagesListPart::do_data_ready(const std::vector<std::shared_ptr<ConversationItem>> &list)",
        "+{",
        "+    dataReady = true;",
        "+",
        "+    // 数据到达后，执行初始加载",
        "+    do_loading_messages();",
        "+}",
