        "+        if (!UserManager::GetInstance()->GetMessages().empty()) {",
        "+            do_loading_messages();",
        "+        } else {",
        "+            // 如果没有数据，设置一个重试机制",
        "+            QTimer::singleShot(1000, this, [this]() {",
        "+                if (!dataReady && !UserManager::GetInstance()->GetMessages().empty()) {",
        "+                    do_loading_messages();",
        "+                }",
        "+            });",
        "+        }",
        "+    // });",
        "+}",
